document.querySelector("body > .qr qr-code").addEventListener("codeRendered",()=>{document.querySelector(".qr qr-code").shadowRoot.querySelector("#qr-container").style="margin: 7px 0 0 7px",document.querySelector("body > .qr qr-code").animateQRCode("MaterializeIn")}),document.querySelector("body > .qr").addEventListener("click",()=>{document.querySelector("body > .qr").classList.remove("show")}),document.addEventListener("click",async e=>{if(!e.target.closest('form span[type="qr"]')&&!e.target.closest('form button[type="copy"]'))return;const t=document.querySelector("#pasted_url");if(e.target.closest('form button[type="qr"]')&&(document.querySelector("body > .qr").classList.add("show"),document.querySelector(".qr qr-code").setAttribute("contents",t.getAttribute("data-value"))),e.target.closest('form span[type="copy"]')){try{if(!navigator.clipboard)throw new Error("Clipboard API not supported");await navigator.clipboard.writeText(t.getAttribute("data-value")),t.value="copied url to clipboard"}catch(e){console.error("Failed to copy: ",e),t.value="failed to copy url to clipboard"}setTimeout(()=>{t.value=t.getAttribute("data-value")},850)}});